void I_Park(void)
{
	/*Park变换，电流由两相旋转坐标系到两相静止坐标系*/
	/*输入变量：VoltageD,VoltageQ, AngleSin,AngleCos,输出变量VoltageX,VoltageY*/
	/*
		VoltageX=VoltageD*AngleCos-VoltageQ*AngleSin;
		VoltageY=VoltageD*AngleSin+VoltageQ*AngleCos;
	*/
	int Temp1,Temp2;
	Temp1=MotorControl.VoltageD;
	Temp2=MotorControl.VoltageQ;
	MotorControl.VoltageX=((Temp1*MotorControl.AngleCos)-(Temp2*MotorControl.AngleSin))>>14;
	MotorControl.VoltageY=((Temp2*MotorControl.AngleCos)+(Temp1*MotorControl.AngleSin))>>14;
}


void MyPark(void)
{
	/*Park变换，电流由两相静止坐标系到两相旋转坐标系*/
	/*输入变量：CurrentX,CurrentY, AngleSin,AngleCos,输出变量CurrentD,CurrentQ*/
	/*
		CurrentD=CurrentX*AngleCos+CurrentY*AngleSin;
		CurrentQ=-CurrentX*AngleSin+CurrentY*AngleCos;
	*/
	MotorControl.CurrentD=(long int)((long int)(MotorControl.CurrentX*MotorControl.AngleCos)+(long int)(MotorControl.CurrentY*MotorControl.AngleSin))>>14;
	MotorControl.CurrentQ=(long int)((long int)(MotorControl.CurrentY*MotorControl.AngleCos)-(long int)(MotorControl.CurrentX*MotorControl.AngleSin))>>14;
}



void SinCosGet2(void)
{
	int Temp;
	Temp=MotorControl.StopAngle+128;
	while(Temp>=256)Temp=Temp-256;
	while(Temp<0)Temp=Temp+256;
	MotorControl.AngleSin=SinTab[Temp];
	Temp=Temp+64;
	while(Temp>=256)Temp=Temp-256;
	MotorControl.AngleCos=SinTab[Temp];
}

/*******************************************************************************
 函数名称：    void lowPass_filter(stru_RC_Def *rc, s16 signal)
 功能描述：    低通滤波器
 操作的表：    无
 输入参数：    无
 输出参数：    无
 返 回 值：    无
 多任务访问:   该函数涉及全局表项操作，不可重入
 其它说明：
 修改日期      版本号          修改人            修改内容
 -----------------------------------------------------------------------------
 2022/06/15      V1.0         LiuH              创建
 *******************************************************************************/
s16 lowPass_filter(stru_RC_Def *rc, s16 signal)
{
    s32 wkg;
    wkg = (signal - (s16)(rc->yk_1 >> 16)) * (rc->coef);
    rc->yk_1 += wkg;
    return(rc->yk_1 >> 16);
}


