void I_Clarke(void)
{
	/*Clarke反变化，电压由两相静止坐标系到三相静止坐标系*/
	/*输入变量：VoltageX,VoltageY；输出变量VoltageU,VoltageV,VoltageW*/
	/*
		VoltageU=VoltageX;
		VoltageW=(-VoltageX+sqrt(3)*VoltageY)/2;
		VolgateV=-VoltageU-VoltageW;
	*/
	long int Temp;
	MotorControl.VoltageU=MotorControl.VoltageX;
	Temp=MotorControl.VoltageY;
	Temp=(Temp*28377)>>14;
	Temp=-1*Temp;
	MotorControl.VoltageW=(Temp-MotorControl.VoltageX)>>1;
	Temp=-1*MotorControl.VoltageU;
	MotorControl.VoltageV=(Temp-MotorControl.VoltageW);
}

void Current_I_Clarke(void)
{
	/*Clarke反变化，电压由两相静止坐标系到三相静止坐标系*/
	/*输入变量：OutputCurrentX,OutputCurrentY；输出变量OutputCurrentU,OutputCurrentV,OutputCurrentW*/
	/*
		OutputCurrentU=OutputCurrentX;
		OutputCurrentW=(-OutputCurrentX+sqrt(3)*OutputCurrentY)/2;
		OutputCurrentV=-OutputCurrentU-OutputCurrentW;
	*/
	long int Temp;
	MotorControl.OutputCurrentU=MotorControl.OutputCurrentX;
	Temp=MotorControl.OutputCurrentY;
	Temp=(Temp*28377)>>14;
	Temp=-1*Temp;
	MotorControl.OutputCurrentW=(Temp-MotorControl.VoltageX)>>1;
	MotorControl.OutputCurrentV=-1*MotorControl.OutputCurrentU-MotorControl.OutputCurrentW;
}

void MyClarke(void)
{
	/*Clarke变换，电流由三相静止坐标系到两相静止坐标系*/
	/*输入变量：CurrentU,CurrentV,CurrentW,输出变量CurrentX,CurrentY*/
	/* Ix=Iu;Iy=(2Iv+Iu)/sqrt(3); */
	long int Temp;
	MotorControl.CurrentX=MotorControl.CurrentU;
	Temp=2*MotorControl.CurrentV+MotorControl.CurrentU;
	MotorControl.CurrentY=(Temp*18918)>>15;
}

void OpenLoop(void)				//开环控制
{
	int Temp;
	Motor.Factory.SwitchFrequency=150;
	MotorControl.OpenLoopAngleAdd=18*4096/Motor.Factory.SwitchFrequency;
	MotorControl.OpenLoopAngle=MotorControl.OpenLoopAngle+MotorControl.OpenLoopAngleAdd;
	Temp=360*4096;
	if(MotorControl.OpenLoopAngle>=Temp)
	{
		MotorControl.OpenLoopAngle=MotorControl.OpenLoopAngle-Temp;		//720*256
	}
	if(MotorControl.OpenLoopAngle<0)
	{
		MotorControl.OpenLoopAngle=MotorControl.OpenLoopAngle+Temp;		//720*256
	}
	Temp=MotorControl.OpenLoopAngle/360/16;
	MotorControl.MotorAngle=Temp;
	while(MotorControl.MotorAngle>=256)MotorControl.MotorAngle=MotorControl.MotorAngle-256;
	while(MotorControl.MotorAngle<0)
	{
		MotorControl.MotorAngle=MotorControl.MotorAngle+256;
	}
	MotorControl.AngleSin=SinTab[MotorControl.MotorAngle];
	MotorControl.MotorAngle=MotorControl.MotorAngle+64;
