void BrusslessStart(void)
{
		//4-5-1-3-2-6:抖
	//5-1-3-2-6-4:
	//1-3-2-6-4-5:不行
	//3-2-6-4-5-1:  80A
	//2-6-4-5-1-3: 不运行
	//6-4-5-1-3-2：反相序
	GPIO_InitTypeDef GPIO_InitStructure;
	int Temp;
	MCPWM_PRT = 0x0000DEAD;
	MotorControl.OpenLoopVoltage=100;
	if(MotorControl.OpenLoopVoltage>1000)MotorControl.OpenLoopVoltage=1000;
	Temp=MotorControl.OpenLoopVoltage*PWM_PERIOD/1000;
	MCPWM_TH00 =-Temp;
	MCPWM_TH01 =Temp;
	MCPWM_TH10 =-Temp;
	MCPWM_TH11 =Temp;
	MCPWM_TH20 =-Temp;
	MCPWM_TH21 =Temp;
	switch(MotorControl.HallState)
	{
		case 5:  //A+,B-
				// A相PWM，B相ON C相悬空  ；检测下降沿过零事件
				// A PWM | B on | C float
				//A-B
				MCPWM_IO01 =  DRIVER_POLARITY |0x1c00;
				MCPWM_IO23 =  DRIVER_POLARITY |0x0c;	
				MotorControl.CurrentMeasure=3;
		break;
		case 1: //A+,C-
				// A相PWM，B相悬空 C ON；检测上升沿过零事件
				// A pwm | B float | C ON
				//A-C
				MCPWM_IO01 = DRIVER_POLARITY | (0x0c00);
