void PedelTorqueHandle(void)
{
	int Temp;
	Motor.Monitor.AD1ADValue=ADC0_DAT6;
	Temp=(Motor.Monitor.AD1ADValue*Motor.Passensors.PasTorqueAmpRatio*499/100)>>5;
	if(Motor.Monitor.AD1ADValue>=Temp)
	{
		MotorControl.PedelTorque.NTime=Motor.Passensors.TorqueIncreaseReactionTime*3/2;
	}
	else
	{
		MotorControl.PedelTorque.NTime=Motor.Passensors.TorqueDecreaseReactionTime*3/2;
	}
	MotorControl.PedelTorque.NIn=Temp;
	FilterCalculate(&MotorControl.PedelTorque);
	Motor.Monitor.TorqueValtage=MotorControl.PedelTorque.NOut/10;
	if(Motor.KingMeter.Enable==2)
	{
		switch(Motor.Passensors.ZeroTorqueDetectMode)
		{
			case 0:			//采用固定值
				if(Motor.Monitor.TorqueValtage>=(Motor.Passensors.TorqueStartUpIncrementValue+Motor.Passensors.ZeroTorqueFixedValue))
				{
					Motor.Passensors.TorqueStartEnable=1;
				}
				else
				{
					Motor.Passensors.TorqueStartEnable=0;
				}
				if(Motor.Passensors.TorqueStartEnable)
				{
					Motor.Monitor.Torque=(Motor.Monitor.TorqueValtage-Motor.Passensors.ZeroTorqueFixedValue)*50/Motor.Passensors.TorqueIncrementValue50Nm;
					if(Motor.Monitor.Torque<0)Motor.Monitor.Torque=0;
					Motor.Monitor.MotorCurrentCommand=Motor.Monitor.Torque*Motor.Passensors.PasSpeedRatio/500;
				}
				else
				{
					Motor.Monitor.Torque=0;
				}
				if(Motor.Monitor.MotorCurrentCommand>((Motor.Battery.CurrentLimit*Motor.KingMeter.PWMValue)>>8))Motor.Monitor.MotorCurrentCommand=(Motor.Battery.CurrentLimit*Motor.KingMeter.PWMValue)>>8;
				if(Motor.Monitor.MotorCurrentCommand<(Motor.Passensors.SpeedSignalMaintancePower*Motor.Battery.UnitCurrentLimit/1000))
					Motor.Monitor.MotorCurrentCommand=(Motor.Passensors.SpeedSignalMaintancePower*Motor.Battery.UnitCurrentLimit/1000);
			break;
			case 1:			//动态找最小零点
				if(Motor.Passensors.ZeroTorqueDetectValue==0)Motor.Passensors.ZeroTorqueDetectValue=MotorControl.PedelTorque.NIn/10;
				else
				{
					if((MotorControl.PedelTorque.NIn/10)<Motor.Passensors.ZeroTorqueDetectValue)Motor.Passensors.ZeroTorqueDetectValue=MotorControl.PedelTorque.NIn/10;
				}
				Motor.Passensors.TorqueStartUpIncrementValue=10;
				if(Motor.Monitor.TorqueValtage>=(Motor.Passensors.TorqueStartUpIncrementValue+Motor.Passensors.ZeroTorqueDetectValue))
				{
					Motor.Passensors.TorqueStartEnable=1;
				}
				else
				{
					Motor.Passensors.TorqueStartEnable=0;
				}
				if(Motor.Passensors.TorqueStartEnable)
				{
					Motor.Monitor.Torque=(Motor.Monitor.TorqueValtage-Motor.Passensors.ZeroTorqueDetectValue)*50/Motor.Passensors.TorqueIncrementValue50Nm;
					if(Motor.Monitor.Torque<0)Motor.Monitor.Torque=0;
					Motor.Monitor.MotorCurrentCommand=Motor.Monitor.Torque*Motor.Passensors.PasSpeedRatio/500;
				}
				else
				{
					Motor.Monitor.Torque=0;
				}
				if(Motor.Monitor.MotorCurrentCommand>((Motor.Battery.CurrentLimit*Motor.KingMeter.PWMValue)>>8))Motor.Monitor.MotorCurrentCommand=(Motor.Battery.CurrentLimit*Motor.KingMeter.PWMValue)>>8;
				if(Motor.Monitor.MotorCurrentCommand<(Motor.Passensors.SpeedSignalMaintancePower*Motor.Battery.UnitCurrentLimit/1000))
					Motor.Monitor.MotorCurrentCommand=(Motor.Passensors.SpeedSignalMaintancePower*Motor.Battery.UnitCurrentLimit/1000);
			break;
		}
	}
	else
	{
		if(Motor.KingMeter.SpeedTime<=3500)Motor.Monitor.MotorCurrentCommand=Motor.Battery.CurrentLimit;
		else Motor.Monitor.MotorCurrentCommand=50;
	}


}

void BicycleSpeedCal(void)
{
	int Temp;
	if(Motor.KingMeter.SpeedTime<3500)
		Temp=36*Motor.SpeedSensors.WheelPeriMeter/Motor.KingMeter.SpeedTime;
	else
		Temp=0;

	Motor.Monitor.BicycleSpeed=Temp;

}

void SpeedLimitCal(void)
{
	//Motor.SpeedSensors.SpeedLimitValue=250;
	//Motor.KingMeter.PWMValue=255;

	if(Motor.SpeedSensors.SpeedLimitFunction==1)
	{
		if(MotorControl.RunState||MotorControl.RunRequest)
		{
			if(Motor.Monitor.BicycleSpeed<(Motor.SpeedSensors.SpeedLimitValue-10))
			{
				if(Motor.SpeedSensors.SpeedLimitAccTime<100)Motor.SpeedSensors.SpeedLimitAccTime++;
				else
				{
					Motor.SpeedSensors.SpeedLimitAccTime=0;
					if(Motor.Factory.PWMValue<Motor.KingMeter.PWMValue)Motor.Factory.PWMValue++;
					else Motor.Factory.PWMValue=Motor.KingMeter.PWMValue;

				}
			}
			else
			{
				Motor.SpeedSensors.SpeedLimitAccTime=0;
			}
			if(Motor.Monitor.BicycleSpeed>(Motor.SpeedSensors.SpeedLimitValue+10))
			{
				if(Motor.SpeedSensors.SpeedLimitDecTime<100)Motor.SpeedSensors.SpeedLimitDecTime++;
				else
				{
					Motor.SpeedSensors.SpeedLimitDecTime=0;
					Motor.Factory.PWMValue=Motor.Factory.PWMValue-1;
					if(Motor.Factory.PWMValue<10)Motor.Factory.PWMValue=10;
				}
			}
			else
			{
				Motor.SpeedSensors.SpeedLimitDecTime=0;
			}
			if(Motor.Factory.PWMValue>Motor.KingMeter.PWMValue)Motor.Factory.PWMValue=Motor.KingMeter.PWMValue;
		}
		else
		{
			Motor.Factory.PWMValue=Motor.KingMeter.PWMValue;
			Motor.SpeedSensors.SpeedLimitAccTime=0;
			Motor.SpeedSensors.SpeedLimitDecTime=0;
		}
	}
	else
	{
		Motor.Factory.PWMValue=Motor.KingMeter.PWMValue;
		Motor.SpeedSensors.SpeedLimitAccTime=0;
		Motor.SpeedSensors.SpeedLimitDecTime=0;
	}
	if(Motor.KingMeter.Enable==0)Motor.KingMeter.PWMValue=Motor.General.SpeedStepLimit[1]*256/1000;
