		MotorControl.CurrentPID.MinOutput=0x7E00/10;
		if(MotorControl.CurrentPID.MinOutput>MotorControl.CurrentPID.MaxOutput)MotorControl.CurrentPID.MinOutput=MotorControl.CurrentPID.MaxOutput;
