		MotorControl.CurrentPID.FeedBack=Motor.Monitor.DCCurrent;
		MotorControl.CurrentPID.Kp=Motor.Factory.CurrentKp;
		MotorControl.CurrentPID.Ki=Motor.Factory.CurrentTi;
