void SinCosGet(void)
{
	if(MotorControl.HallAngle>=2949120)MotorControl.HallAngle=MotorControl.HallAngle-2949120;
	if(MotorControl.HallAngle<0)MotorControl.HallAngle=MotorControl.HallAngle+2949120;
	MotorControl.MotorAngle=MotorControl.HallAngle/360/32;
	while(MotorControl.MotorAngle>=256)MotorControl.MotorAngle=MotorControl.MotorAngle-256;
	while(MotorControl.MotorAngle<0)MotorControl.MotorAngle=MotorControl.MotorAngle+256;
	MotorControl.StopAngle=MotorControl.MotorAngle;
	MotorControl.AngleSin=SinTab[MotorControl.MotorAngle];
	MotorControl.MotorAngle=MotorControl.MotorAngle+64;
	while(MotorControl.MotorAngle>=256)MotorControl.MotorAngle=MotorControl.MotorAngle-256;
	while(MotorControl.MotorAngle<0)MotorControl.MotorAngle=MotorControl.MotorAngle+256;
	MotorControl.AngleCos=SinTab[MotorControl.MotorAngle];
}

void TorqueLoop(void)
{
	int Temp;

	TorqueReference();
	//Temp=SpeedPID.Output/1000;

	MotorControl.CurrentQPID.Reference=Temp;//(CurrentQPID.Reference*100+Temp*400)/500;;//FIRCurrentQReference.Output;//(CurrentQPID.Reference*100+SpeedPID.Output*400)/500;//FIRCurrentQReference.Output;////CurrentQRefFilter.NOut;			////
	MotorControl.CurrentDPID.Reference=0;
 	MotorControl.CurrentQPID.FeedBack=MotorControl.CurrentQ;//(CurrentQPID.FeedBack*100+CurrentQ*400)/500;//(CurrentQPID.FeedBack*100+CurrentQ*400)/500;;
	MotorControl.CurrentDPID.FeedBack=MotorControl.CurrentD;//(CurrentDPID.FeedBack*100+CurrentD*400)/500;//(CurrentDPID.FeedBack*100+CurrentD*400)/500;
	//Motor.Factory.CurrentKp=10;
	//Motor.Factory.CurrentTi=30;
	MotorControl.CurrentQPID.Kp=Motor.Factory.CurrentKp;//+SpeedACTFilter.NOut>>12;
	MotorControl.CurrentDPID.Kp=Motor.Factory.CurrentKp;
	MotorControl.CurrentQPID.Ki=Motor.Factory.CurrentTi;
 	MotorControl.CurrentDPID.Ki=Motor.Factory.CurrentTi;
	MotorControl.CurrentQPID.MaxOutput=MotorControl.CurrentPID.Output;
	MotorControl.CurrentQPID.MinOutput=0;
	//if(CurrentQPID.MinOutput>CurrentQPID.MaxOutput)CurrentQPID.MinOutput=CurrentQPID.MaxOutput;
	MotorControl.CurrentDPID.MaxOutput=MotorControl.CurrentPID.Output;//(0x7F00*Motor.Factory.PWMValue)>>8;
	MotorControl.CurrentDPID.MinOutput=-1*MotorControl.CurrentDPID.MaxOutput;
 	PidCalculation(&MotorControl.CurrentQPID);
	PidCalculation(&MotorControl.CurrentDPID);
	MotorControl.VoltageD=MotorControl.CurrentDPID.Output;

 	MotorControl.VoltageQ=MotorControl.CurrentQPID.Output;;
}

