void GetADMeasure(void)
{
	int Temp[3],i,Value;
	//Motor.Factory.CurrentScale=1488;//172
	switch(MotorControl.CurrentMeasure)
	{
		case 1:				//电流采样BC，扇区1,6
            MotorControl.CurrentV = MotorControl.CurrentVOffset-ADC0_DAT1;
						MotorControl.CurrentW = MotorControl.CurrentWOffset-ADC0_DAT2;
            MotorControl.CurrentU = -1*MotorControl.CurrentV-MotorControl.CurrentW;
						MotorControl.CurrentU=(MotorControl.CurrentU*Motor.Factory.CurrentScale);
						MotorControl.CurrentV=(MotorControl.CurrentV*Motor.Factory.CurrentScale);
						MotorControl.CurrentW=(MotorControl.CurrentW*Motor.Factory.CurrentScale);						
		break;
		case 2:				//电流采样AC，扇区2,3
						MotorControl.CurrentU = MotorControl.CurrentUOffset-ADC0_DAT0;
						MotorControl.CurrentW = MotorControl.CurrentWOffset-ADC0_DAT2;
            MotorControl.CurrentV = -1*MotorControl.CurrentU-MotorControl.CurrentW;
						MotorControl.CurrentU=(MotorControl.CurrentU*Motor.Factory.CurrentScale);
						MotorControl.CurrentV=(MotorControl.CurrentV*Motor.Factory.CurrentScale);
						MotorControl.CurrentW=(MotorControl.CurrentW*Motor.Factory.CurrentScale);
		break;
		case 3:				//电流采样AB，扇区4,5
						MotorControl.CurrentU = MotorControl.CurrentUOffset-ADC0_DAT0;
						MotorControl.CurrentV = MotorControl.CurrentVOffset-ADC0_DAT1;
            MotorControl.CurrentW = -1*MotorControl.CurrentU-MotorControl.CurrentV;
						MotorControl.CurrentU=(MotorControl.CurrentU*Motor.Factory.CurrentScale);
						MotorControl.CurrentV=(MotorControl.CurrentV*Motor.Factory.CurrentScale);
						MotorControl.CurrentW=(MotorControl.CurrentW*Motor.Factory.CurrentScale);
		break;
	}
	if(MotorControl.CurrentMeausureEnable)
	{
		MotorControl.CurrentU=MotorControl.CurrentU;
		MotorControl.CurrentV=MotorControl.CurrentV;
		MotorControl.CurrentW=MotorControl.CurrentW;
	}
	else
	{
		MotorControl.CurrentU=0;
		MotorControl.CurrentV=0;
		MotorControl.CurrentW=0;
	}


}






