void SinCosGet(void)
{
	if(MotorControl.HallAngle>=2949120)MotorControl.HallAngle=MotorControl.HallAngle-2949120;
	if(MotorControl.HallAngle<0)MotorControl.HallAngle=MotorControl.HallAngle+2949120;
	MotorControl.MotorAngle=MotorControl.HallAngle/360/32;
	while(MotorControl.MotorAngle>=256)MotorControl.MotorAngle=MotorControl.MotorAngle-256;
	while(MotorControl.MotorAngle<0)MotorControl.MotorAngle=MotorControl.MotorAngle+256;
	MotorControl.StopAngle=MotorControl.MotorAngle;
	MotorControl.AngleSin=SinTab[MotorControl.MotorAngle];
	MotorControl.MotorAngle=MotorControl.MotorAngle+64;
	while(MotorControl.MotorAngle>=256)MotorControl.MotorAngle=MotorControl.MotorAngle-256;
	while(MotorControl.MotorAngle<0)MotorControl.MotorAngle=MotorControl.MotorAngle+256;
	MotorControl.AngleCos=SinTab[MotorControl.MotorAngle];
}

