				MotorControl.VoltageQ=(Temp-Motor.Thorttle.StartUpVoltage)*Motor.Thorttle.MaxOutput/1000*0x7F00/(Motor.Thorttle.FullVoltage-Motor.Thorttle.StartUpVoltage);
				MotorControl.VoltageD=0;
				if(MotorControl.VoltageQ>0x7F00)MotorControl.VoltageQ=0x7F00;
				//if(MotorControl.VoltageQ>MotorControl.CurrentPID.Output)MotorControl.VoltageQ=MotorControl.CurrentPID.Output;
			}
			//MotorControl.VoltageQ=0x500;//VoltageQCommand;//(Temp-Motor.Thorttle.StartUpVoltage)*Motor.Thorttle.MaxOutput*0x1FFF/1000/(Motor.Thorttle.FullVoltage-Motor.Thorttle.StartUpVoltage);
			//MotorControl.VoltageD=0;
			VoltageOutput();	

		}
		MotorControl.RunState=1;
		MotorStart();

	}
	else
	{

		MotorStop();
		MotorControl.RunState=0;
	}
	Temp=ABS(ADC0_DAT3-MotorControl.CurrentDCOffset);
	Temp=Temp*Motor.Factory.CurrentScale;
	//MotorControl.CurrentDFilter.NIn=Temp;
	//FilterCalculate(&MotorControl.CurrentDFilter);
	//Motor.Monitor.DCCurrent=MotorControl.CurrentDFilter.NOut;
	Motor.Monitor.DCCurrent=lowPass_filter(&CurrentDFilter,Temp);
	Rttstru.data0 = (MotorControl.HallState*100);   //磁场角度角度   
	Rttstru.data1 = (MotorControl.MotorAngle);    //观察器角度
	Rttstru.data2 = (MotorControl.HallAngle>>8);        //HALL角度

//			  Rttstru.data2 = (stru_BEMF_Check.unBemf_Angle);             //反电动势角度
//			  Rttstru.data0 = (struFOC_CurrLoop.mStatCurrUVW.nPhaseU);    //U相电流角度
//			  Rttstru.data1 = (struFOC_CurrLoop.mStatCurrUVW.nPhaseV);    //U相电流角度
//        Rttstru.data2 = (struFOC_CurrLoop.mStatCurrUVW.nPhaseW);    //U相电流角度

//        Rttstru.data0 = (struBemfVolt.nPhaseU);            //U相反电动势电压
//			  Rttstru.data1 = (struBemfVolt.nPhaseV);            //V相反电动势电压
//        Rttstru.data2 = (struBemfVolt.nPhaseW);            //W相反电动势电压

	SEGGER_RTT_Write(1, &Rttstru, 6);
}


